class CaseFile:
    def __init__(self, case_id):
        self.case_id = case_id
        self.evidence = []
    def add_evidence(self, e):
        self.evidence.append(e)
    def count(self):
        return len(self.evidence)

cf = CaseFile("F1")
cf.add_evidence("e1"); cf.add_evidence("e2")
print("n=", cf.count())

from typing import Protocol

class Scorer(Protocol):
    def score(self, pair: tuple[str, str]) -> float: ...

class FakeScorer:
    def score(self, pair: tuple[str, str]) -> float:
        return 0.5

def run(s: Scorer):
    return s.score(("a", "b"))

print(run(FakeScorer()))

def apply(norm, s):
    return norm(s)

def strip_norm(s):
    return s.strip()

def casefold_norm(s):
    return s.casefold()

print(apply(strip_norm, " Ana "), "|", apply(casefold_norm, "Ana"))

class Repo:
    def __init__(self):
        self._store = {}
    def save(self, obj):
        self._store[obj["client_id"]] = obj
    def get(self, client_id):
        return self._store.get(client_id)

r = Repo()
r.save({"client_id": "C001", "email": "a@ejemplo.pe"})
print(r.get("C001"))

